def field_html(f):
    typ, i, label, data, value, step = f
    if typ == "select":
        return f'<div class="form-group"><label for="{i}">{escape(label)}</label><select id="{i}">' + ''.join(f'<option value="{escape(v)}">{escape(t)}</option>' for v,t in data) + '</select></div>'
    if typ == "textarea": return f'<div class="form-group"><label for="{i}">{escape(label)}</label><textarea id="{i}" placeholder="{escape(data)}" rows="3"></textarea></div>'
    if typ == "checkbox": return f'<div class="form-group check-field"><label><input type="checkbox" id="{i}" {"checked" if value else ""}> {escape(label)}</label></div>'
    val = f' value="{escape(str(value))}"' if value != "" else ""
    return f'<div class="form-group"><label for="{i}">{escape(label)}</label><input type="{typ}" id="{i}" placeholder="{escape(data)}" step="{step}"{val}></div>'

def faq(title, category):
    return [
      (f"How accurate is the {title}?", "The arithmetic follows the formula shown on this page. Real-world accuracy still depends on the measurements, rates, assumptions, and rounding you enter."),
      ("Does this tool save my data?", "No. The calculation runs in your browser and this page does not require an account or send the entered values to a calculation server."),
      ("Can I use the result professionally?", f"Use it as a planning or checking estimate. For high-cost, safety-critical, academic, tax, or regulated decisions, confirm the result with a qualified professional or authoritative {category.lower()} source."),
    ]

