def page(defn):
    slug,title,kind,cat,summary,fields,formula,example,*extra=defn
    caturl=Path(CATS[cat][0]).stem; qs=faq(title,cat); refs=REFS[cat] + ([("Official current rates",extra[0])] if extra else [])
    schema={"@context":"https://schema.org","@graph":[{"@type":"SoftwareApplication","name":title,"description":summary,"applicationCategory":"UtilityApplication","operatingSystem":"Any","url":BASE+slug,"offers":{"@type":"Offer","price":"0","priceCurrency":"USD"}},{"@type":"FAQPage","mainEntity":[{"@type":"Question","name":q,"acceptedAnswer":{"@type":"Answer","text":a}} for q,a in qs]}]}
    faqs=''.join(f'<div class="faq-item"><button class="faq-question">{escape(q)}<span class="icon">+</span></button><div class="faq-answer"><p>{escape(a)}</p></div></div>' for q,a in qs)
    refhtml=''.join(f'<li><a href="{u}" rel="noopener noreferrer">{escape(t)}</a></li>' for t,u in refs)
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="google-site-verification" content="{VERIFY}"><link rel="icon" type="image/svg+xml" href="logo.svg"><title>{escape(title)} – Free Online Tool | TrueCalco</title><meta name="description" content="{escape(summary)} Free, private, and instant with formula, example, FAQs, and references."><link rel="canonical" href="{BASE}{slug}"><meta property="og:title" content="{escape(title)}"><meta property="og:description" content="{escape(summary)}"><meta property="og:type" content="website"><meta property="og:url" content="{BASE}{slug}"><link rel="stylesheet" href="styles.css"><script type="application/ld+json">{json.dumps(schema,separators=(',',':'))}</script></head><body data-calculator="{kind}">{NAV}<main class="site-wrapper"><div class="calc-page"><div class="breadcrumb"><a href="/">Home</a><span>›</span><a href="{caturl}">{escape(cat)}</a><span>›</span><span class="current">{escape(title)}</span></div><div class="calc-header"><h1>{escape(title)}</h1><p>{escape(summary)}</p></div><div class="calc-widget"><div class="calc-form">{''.join(field_html(f) for f in fields)}</div><div class="calc-actions"><button class="calc-btn" onclick="calculate()">Calculate</button><button class="calc-btn-secondary" onclick="resetCalc()">Reset</button></div><div class="calc-result" id="calcResult" aria-live="polite"><div class="result-label" id="resultLabel"></div><div class="result-value" id="resultValue"></div><div class="result-details" id="resultDetails"></div></div></div><section class="content-section"><h2>Formula and method</h2><p>{escape(summary)} The result is calculated with the relationship below and rounded only for display.</p><div class="formula-box"><code>{escape(formula)}</code></div></section><section class="content-section"><h2>Worked example</h2><div class="example-box"><div class="example-title">Example calculation</div><p>{escape(example)}</p></div></section><section class="content-section"><h2>How to use this calculator</h2><ol><li>Enter measurements or values in the labelled fields.</li><li>Keep all inputs in the units shown beside each label.</li><li>Select the relevant method or direction where offered.</li><li>Choose Calculate and review the result plus supporting details.</li></ol></section><section class="content-section"><h2>Assumptions and limitations</h2><p>This is an educational planning tool. It does not automatically account for local building practice, taxes, fees, rounding rules, measurement uncertainty, safety margins, or professional standards unless you enter them. Check important results independently.</p></section><section class="faq-section"><h2>Frequently asked questions</h2>{faqs}</section><section class="content-section"><h2>References and further reading</h2><p>These sources explain relevant standards, methods, or official guidance. References do not imply endorsement.</p><ul class="reference-list">{refhtml}</ul></section></div></main>{FOOT}<script src="expansion-calculators.js" defer></script><script src="share-links.js" defer></script></body></html>'''

