def inject_cards(filename, cat):
    path=ROOT/filename; source=path.read_text(encoding="utf-8"); marker='<!-- EXPANSION-CARDS -->'; items=[d for d in D if d[3]==cat]
    cards=marker+'\n'+''.join(f'<a class="tool-card" href="{d[0]}"><div><h3>{escape(d[1])}</h3><p>{escape(d[4])}</p></div><span class="arrow">→</span></a>' for d in items)+'\n<!-- /EXPANSION-CARDS -->'
    import re
    if marker in source: source=re.sub(r'<!-- EXPANSION-CARDS -->.*?<!-- /EXPANSION-CARDS -->',cards,source,flags=re.S)
    else:
        match=re.search(r'<div class="tools-grid"[^>]*>', source)
        if match:
            pos=match.end(); source=source[:pos]+cards+source[pos:]
    path.write_text(source,encoding="utf-8")
inject_cards("finance-calculators.html","Finance")
inject_cards("conversion-calculators.html","Unit Conversion")

