for p in sorted(ROOT.glob("*.html")):
    if p.name == "404.html": continue
    url=BASE if p.name=="index.html" else BASE+p.stem
    urls.append(f"  <url><loc>{url}</loc><lastmod>2026-07-14</lastmod></url>")
(ROOT/"sitemap.xml").write_text('<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n'+'\n'.join(urls)+'\n</urlset>\n',encoding="utf-8")
print(f"Generated {len(D)} calculators and {len(CATS)-2} category pages; sitemap has {len(urls)} URLs.")
